    let obj = SomeObject()

    let wrapper = ObjCWrapper()
    NSLog("SomeObject address: %p", obj)
    wrapper.sendingMethod(obj)

    Timer.scheduledTimer(withTimeInterval: 5.0, repeats: true) { _ in
        NSLog("SomeObject address: %p", obj)
    }
}
```

